BankStatementLine(models.Model):
    _inherit = 'account.bank.statement.line'

    reconciliation_state = fields.Selection([
        ('ingested', 'Ingested'),
        ('matched', 'Matched'),
        ('ambiguous', 'Ambiguous'),
        ('exception', 'Exception'),
        ('approved_to_post', 'Approved to Post'),
        ('posted', 'Posted'),
        ('quarantined', 'Quarantined')
    ], string='Reconciliation State', default='ingested', tracking=True)

    agent_evidence_pack = fields.Text(string='Agent Evidence Pack (JSON)', help='Grounded matching logic and document links.')
    confidence_score = fields.Float(string='Match Confidence', digits=(1, 4))

    # State Transition Rules
    def action_approve_reconciliation(self):
        for line in self:
            if line.reconciliation_state != 'matched':
                raise UserError(_("Only matched lines can be approved for posting."))
            if not line.agent_evidence_pack:
                raise UserError(_("Cannot approve without a valid evidence pack."))
            line.reconciliation_state = 'approved_to_post'

    def action_quarantine_reconciliation(self, reason):
        for line in self:
            line.write({
                'reconciliation_state': 'quarantined',
                'message_post_reason': reason
            })
            line.message_post(body=_("Quarantined: %s") % reason)

    def action_reset_to_ingested(self):
        for line in self:
            if line.reconciliation_state == 'posted':
                raise UserError(_("Cannot reset a posted transaction."))
            line.reconciliation_state = 'ingested'
            line.agent_evidence_pack = False
            line.confidence_score = 0.0

    # Fail-Closed Override for Standard Post
    def action_bank_reconcile_bank_statement_line(self):
        """Override standard reconcile to enforce agentic gates."""
        for line in self:
            # RED TEAM FIX: Check both state and evidence pack presence
            if not self.env.context.get('manual_override'):
                if line.reconciliation_state != 'approved_to_post':
                    raise UserError(_("Fail-Closed: Posting is blocked. Transaction must be in 'Approved to Post' state."))
                if not line.agent_evidence_pack:
                    raise UserError(_("Fail-Closed: Posting is blocked. Missing required 'Agent Evidence Pack'."))

        res = super(BankStatementLine, self).action_bank_reconcile_bank_statement_line()

        # If successful, move to posted
        for line in self:
            line.reconciliation_state = 'posted'
        return res

AiActionMixin(models.AbstractModel):
    """Mixin for models that support Copilot and OCR actions.

    Inherit this mixin on any business model to get standardized
    action methods for triggering AI jobs.
    """

    _name = 'ipai.ai.action.mixin'
    _description = 'AI Action Mixin'

    def action_ask_copilot(self):
        """Open Copilot chat with current record context."""
        self.ensure_one()
        return {
            'type': 'ir.actions.client',
            'tag': 'ipai_copilot_open',
            'params': {
                'model': self._name,
                'res_id': self.id,
                'action': 'ask',
            },
        }

    def action_copilot_summarize(self):
        """Create a Copilot summary job for this record."""
        self.ensure_one()
        return self._create_ai_job('copilot_summary')

    def action_copilot_suggest_next(self):
        """Ask Copilot to suggest the next workflow step."""
        self.ensure_one()
        return self._create_ai_job('copilot_suggest')

    def action_run_ocr(self):
        """Run OCR on the first attachment of this record."""
        self.ensure_one()
        attachment = self.env['ir.attachment'].search([
            ('res_model', '=', self._name),
            ('res_id', '=', self.id),
            ('mimetype', 'in', ['application/pdf', 'image/png', 'image/jpeg', 'image/tiff']),
        ], limit=1, order='create_date desc')
        if not attachment:
            return {
                'type': 'ir.actions.client',
                'tag': 'display_notification',
                'params': {
                    'title': _('No Attachment'),
                    'message': _('No suitable attachment found for OCR.'),
                    'type': 'warning',
                },
            }
        return self._create_ai_job('ocr_extract', attachment_id=attachment.id)

    def _create_ai_job(self, job_type, trigger='manual', attachment_id=None):
        """Create an AI job record and return a notification action."""
        job = self.env['ipai.ai.job'].create({
            'source_model': self._name,
            'source_record_id': self.id,
            'source_record_name': getattr(self, 'display_name', str(self.id)),
            'job_type': job_type,
            'trigger': trigger,
            'attachment_id': attachment_id,
        })
        _logger.info(
            'AI job created: %s [%s] on %s/%s by %s',
            job.job_type, job.correlation_id,
            self._name, self.id, self.env.user.login,
        )
        return {
            'type': 'ir.actions.client',
            'tag': 'display_notification',
            'params': {
                'title': _('AI Job Created'),
                'message': _('Job %s queued.', job.correlation_id[:8]),
                'type': 'success',
                'next': {
                    'type': 'ir.actions.act_window',
                    'res_model': 'ipai.ai.job',
                    'res_id': job.id,
                    'view_mode': 'form',
                },
            },
        }

= fields.Selection(
        [
            ('auth', 'Authentication'),
            ('network', 'Network'),
            ('service', 'Service Error'),
            ('model', 'Model Error'),
            ('data', 'Data Error'),
            ('timeout', 'Timeout'),
        ],
    )

    # --- Timing ---
    started_at = fields.Datetime()
    completed_at = fields.Datetime()
    duration_ms = fields.Integer(compute='_compute_duration_ms', store=True)

    # --- Retry ---
    retry_count = fields.Integer(default=0)
    max_retries = fields.Integer(default=3)
    last_retry_at = fields.Datetime()

    # --- Linked proposal ---
    proposal_ids = fields.One2many('ipai.ai.proposal', 'job_id')
    proposal_count = fields.Integer(compute='_compute_proposal_count')

    @api.depends('correlation_id', 'job_type')
    def _compute_display_name(self):
        for rec in self:
            short_id = (rec.correlation_id or '')[:8]
            job_label = dict(rec._fields['job_type'].selection).get(rec.job_type, '')
            rec.display_name = f"{job_label} [{short_id}]"

    @api.depends('started_at', 'completed_at')
    def _compute_duration_ms(self):
        for rec in self:
            if rec.started_at and rec.completed_at:
                delta = rec.completed_at - rec.started_at
                rec.duration_ms = int(delta.total_seconds() * 1000)
            else:
                rec.duration_ms = 0

    def _compute_proposal_count(self):
        for rec in self:
            rec.proposal_count = len(rec.proposal_ids)

    # --- State transitions ---

    def action_start(self):
        self.ensure_one()
        if self.state != 'queued':
            raise UserError(_('Can only start a queued job.'))
        self.write({
            'state': 'running',
            'started_at': fields.Datetime.now(),
        })

    def action_complete(self, result_payload=None, confidence=0.0):
        self.ensure_one()
        vals = {
            'state': 'done',
            'completed_at': fields.Datetime.now(),
            'result_payload': result_payload,
            'confidence': confidence,
        }
        threshold = float(
            self.env['ir.config_parameter'].sudo().get_param(
                'ipai.copilot_actions.review_threshold', '0.7'
            )
        )
        if confidence and confidence < threshold:
            vals['state'] = 'needs_review'
            vals['needs_human_review'] = True
            vals['review_reason'] = _('Confidence %.0f%% below threshold %.0f%%',
                                      confidence * 100, threshold * 100)
        self.write(vals)

    def action_fail(self, error_message, error_class=None):
        self.ensure_one()
        self.write({
            'state': 'failed',
            'completed_at': fields.Datetime.now(),
            'error_message': error_message,
            'error_class': error_class,
        })

    def action_retry(self):
        self.ensure_one()
        if self.retry_count >= self.max_retries:
            raise UserError(_('Maximum retries (%s) reached.', self.max_retries))
        self.write({
            'state': 'queued',
            'retry_count': self.retry_count + 1,
            'last_retry_at': fields.Datetime.now(),
            'error_message': False,
            'error_class': False,
        })

    def action_cancel(self):
        self.filtered(lambda j: j.state in ('queued', 'failed', 'needs_review')).write({
            'state': 'cancelled',
        })

    def action_view_proposals(self):
        self.ensure_one()
        return {
            'type': 'ir.actions.act_window',
            'name': _('AI Proposals'),
            'res_model': 'ipai.ai.proposal',
            'domain': [('job_id', '=', self.id)],
            'view_mode': 'list,form',
        }

OcrClientService(models.AbstractModel):
    """Service model for Azure Document Intelligence operations."""

    _name = 'ipai.ocr.client'
    _description = 'Document Intelligence Client'

    def submit_ocr_job(self, job):
        """Submit an OCR job to Document Intelligence.

        Args:
            job: ipai.ai.job record with attachment_id set.

        Returns:
            ipai.ocr.result record.
        """
        job.action_start()

        attachment = job.attachment_id
        if not attachment:
            job.action_fail('No attachment linked to job.', 'data')
            raise UserError(_('No attachment linked to OCR job.'))

        if attachment.mimetype not in SUPPORTED_MIMETYPES:
            job.action_fail(
                _('Unsupported file type: %s', attachment.mimetype), 'data'
            )
            raise UserError(_('Unsupported file type for OCR: %s', attachment.mimetype))

        config = self._get_config()
        if not config:
            job.action_fail('Document Intelligence not configured.', 'auth')
            raise UserError(_('Document Intelligence is not configured.'))

        extraction_mode = self._determine_mode(job)
        model_id = MODEL_MAP.get(extraction_mode, 'prebuilt-read')

        try:
            endpoint = config.endpoint.rstrip('/')
            api_key = os.getenv('AZURE_DI_API_KEY') or os.getenv('AZURE_DOC_INTEL_KEY', '')
            if not api_key:
                job.action_fail('Missing env var AZURE_DI_API_KEY.', 'auth')
                return None

            api_version = self.env['ir.config_parameter'].sudo().get_param(
                'ipai.doc_intelligence.api_version', '2024-11-30'
            )
            url = (
                f"{endpoint}/documentintelligence/documentModels/{model_id}"
                f":analyze?api-version={api_version}"
            )
            headers = {
                'Ocp-Apim-Subscription-Key': api_key,
                'Content-Type': attachment.mimetype,
            }
            file_data = base64.b64decode(attachment.datas)

            resp = requests.post(url, headers=headers, data=file_data, timeout=30)
            resp.raise_for_status()

            operation_url = resp.headers.get('Operation-Location')
            if not operation_url:
                job.action_fail('No Operation-Location in DI response.', 'service')
                return None

            result_data = self._poll_result(operation_url, api_key)
            ocr_result = self._normalize_result(job, result_data, extraction_mode, model_id)

            confidence = ocr_result.overall_confidence
            job.write({
                'external_job_id': ocr_result.di_operation_id,
                'model_name': model_id,
                'model_version': api_version,
            })
            job.action_complete(
                result_payload={'ocr_result_id': ocr_result.id},
                confidence=confidence,
            )
            return ocr_result

        except requests.exceptions.Timeout:
            job.action_fail('Document Intelligence request timed out.', 'timeout')
        except requests.exceptions.ConnectionError as e:
            job.action_fail(_('Connection error: %s', str(e)), 'network')
        except requests.exceptions.HTTPError as e:
            job.action_fail(_('HTTP error: %s', str(e)), 'service')
        except Exception as e:
            _logger.exception('OCR job %s failed unexpectedly', job.correlation_id)
            job.action_fail(_('Unexpected error: %s', str(e)), 'service')
        return None

    def _get_config(self):
        """Get Document Intelligence configuration singleton."""
        return self.env['ipai.doc.digitization.config'].search([], limit=1)

    def _determine_mode(self, job):
        """Determine extraction mode based on job type and config."""
        mode_map = {
            'ocr_read': 'read',
            'ocr_extract': 'prebuilt_invoice',
            'ocr_classify': 'layout',
            'finance_draft': 'prebuilt_invoice',
            'finance_review': 'prebuilt_receipt',
        }
        return mode_map.get(job.job_type, 'read')

    def _poll_result(self, operation_url, api_key, max_attempts=30, interval=2):
        """Poll DI operation until complete or timeout."""
        headers = {'Ocp-Apim-Subscription-Key': api_key}
        for attempt in range(max_attempts):
            resp = requests.get(operation_url, headers=headers, timeout=10)
            resp.raise_for_status()
            data = resp.json()
            status = data.get('status', '')
            if status == 'succeeded':
                return data.get('analyzeResult', {})
            if status == 'failed':
                error = data.get('error', {}).get('message', 'Unknown DI error')
                raise UserError(_('Document Intelligence failed: %s', error))
            time.sleep(interval)
        raise UserError(_('Document Intelligence timed out after %d attempts.', max_attempts))

    def _normalize_result(self, job, result_data, extraction_mode, model_id):
        """Normalize DI output into ipai.ocr.result record."""
        pages = result_data.get('pages', [])
        content = result_data.get('content', '')
        tables = result_data.get('tables', [])
        kv_pairs = result_data.get('keyValuePairs', [])
        documents = result_data.get('documents', [])

        # Extract fields from first document if present
        extracted_fields = {}
        field_confidences = {}
        if documents:
            doc = documents[0]
            for field_name, field_data in doc.get('fields', {}).items():
                extracted_fields[field_name] = field_data.get('valueString',
                    field_data.get('valueNumber',
                    field_data.get('valueDate',
                    field_data.get('content', ''))))
                if isinstance(field_data.get('value'), dict):
                    extracted_fields[field_name] = field_data['value']
                field_confidences[field_name] = field_data.get('confidence', 0)

        # Compute overall confidence
        confidences = list(field_confidences.values()) if field_confidences else [
            p.get('confidence', 0) for p in pages if 'confidence' in p
        ]
        overall = sum(confidences) / len(confidences) if confidences else 0.0

        return self.env['ipai.ocr.result'].create({
            'job_id': job.id,
            'attachment_id': job.attachment_id.id,
            'extraction_mode': extraction_mode,
            'di_model_id': model_id,
            'di_api_version': result_data.get('apiVersion', ''),
            'page_count': len(pages),
            'raw_text': content,
            'text_blocks': [
                {'page': p.get('pageNumber'), 'lines': [
                    l.get('content', '') for l in p.get('lines', [])
                ]} for p in pages
            ],
            'tables': [
                {
                    'row_count': t.get('rowCount', 0),
                    'column_count': t.get('columnCount', 0),
                    'cells': [
                        {
                            'row': c.get('rowIndex'),
                            'col': c.get('columnIndex'),
                            'content': c.get('content', ''),
                        } for c in t.get('cells', [])
                    ],
                } for t in tables
            ],
            'key_value_pairs': [
                {
                    'key': kv.get('key', {}).get('content', ''),
                    'value': kv.get('value', {}).get('content', ''),
                    'confidence': kv.get('confidence', 0),
                } for kv in kv_pairs
            ],
            'extracted_fields': extracted_fields,
            'overall_confidence': overall,
            'field_confidences': field_confidences,
            'processed_at': fields.Datetime.now(),
        })

ResConfigSettingsActions(models.TransientModel):
    """Action methods for General Settings — split out for clarity.

    These methods live on ``res.config.settings`` via ``_inherit`` and are
    invoked from buttons in the settings XML view.
    """

    _inherit = "res.config.settings"

    # ------------------------------------------------------------------
    # Helper — singleton lookup
    # ------------------------------------------------------------------
    def _get_or_create_singleton(self, model_name, defaults=None):
        """Return the first record of *model_name*, creating one if none exists."""
        record = self.env[model_name].search([], limit=1)
        if not record:
            record = self.env[model_name].create(defaults or {})
        return record

    # ------------------------------------------------------------------
    # Actions
    # ------------------------------------------------------------------
    def action_open_api_keys(self):
        """Open the API Keys management view."""
        return {
            "type": "ir.actions.act_url",
            "url": "/odoo/settings/api-keys",
            "target": "self",
        }

    def action_open_foundry_provider(self):
        """Open Foundry provider configuration."""
        config = self._get_or_create_singleton(
            "ipai.foundry.provider.config",
            {"name": "Default", "endpoint": ""},
        )
        return {
            "type": "ir.actions.act_window",
            "name": _("Foundry Configuration"),
            "res_model": "ipai.foundry.provider.config",
            "view_mode": "form",
            "target": "new",
            "res_id": config.id,
        }

    def action_open_doc_digitization_provider(self):
        """Open Document Digitization configuration."""
        config = self._get_or_create_singleton(
            "ipai.doc.digitization.config",
            {"name": "Default"},
        )
        return {
            "type": "ir.actions.act_window",
            "name": _("Document Digitization Configuration"),
            "res_model": "ipai.doc.digitization.config",
            "view_mode": "form",
            "target": "new",
            "res_id": config.id,
        }

    def action_apply_google_oauth(self):
        """Create or update the Google Workspace auth.oauth.provider record."""
        self.ensure_one()
        ICP = self.env["ir.config_parameter"].sudo()
        enabled = ICP.get_param("ipai.oauth.google.enabled", "False") == "True"
        client_id = ICP.get_param("ipai.oauth.google.client_id", "")
        domain = ICP.get_param("ipai.oauth.google.workspace_domain", "w9studio.net")

        if not client_id:
            return {
                "type": "ir.actions.client",
                "tag": "display_notification",
                "params": {
                    "title": _("Google OAuth"),
                    "message": _("Client ID is empty. Configure it before enabling the provider."),
                    "type": "warning",
                    "sticky": False,
                },
            }

        Provider = self.env["auth.oauth.provider"].sudo()
        google = Provider.search([("name", "=like", "Google Workspace%")], limit=1)

        # Always compute auth_endpoint from constant base + domain.
        # This is idempotent: repeated calls never double-append ?hd=.
        _GOOGLE_AUTH_BASE = "https://accounts.google.com/o/oauth2/v2/auth"
        auth_endpoint = _GOOGLE_AUTH_BASE
        if domain:
            auth_endpoint = f"{_GOOGLE_AUTH_BASE}?hd={domain}"

        vals = {
            "name": "Google Workspace (W9 Studio)",
            "enabled": enabled,
            "client_id": client_id,
            "auth_endpoint": auth_endpoint,
            "validation_endpoint": "https://www.googleapis.com/oauth2/v3/tokeninfo",
            "scope": "openid email profile",
            "data_endpoint": "https://www.googleapis.com/oauth2/v1/userinfo?access_token=",
            "css_class": "fa fa-fw fa-google",
            "body": "Log in with Google",
            "sequence": 20,
        }

        if google:
            google.write(vals)
        else:
            Provider.create(vals)

        msg = _("Google Workspace provider updated.") if google else _("Google Workspace provider created.")
        return {
            "type": "ir.actions.client",
            "tag": "display_notification",
            "params": {"title": _("Google OAuth"), "message": msg, "type": "success", "sticky": False},
        }

    def action_test_foundry_connection(self):
        """Test the Foundry endpoint connection from Settings."""
        config = self.env["ipai.foundry.provider.config"].search([], limit=1)
        if not config:
            return {
                "type": "ir.actions.client",
                "tag": "display_notification",
                "params": {
                    "title": _("Foundry Connection Test"),
                    "message": _("No Foundry configuration found. Configure it first."),
                    "type": "warning",
                    "sticky": False,
                },
            }
        return config.action_test_connection()

    def action_test_doc_digitization_connection(self):
        """Test the OCR / Document Intelligence endpoint from Settings."""
        config = self.env["ipai.doc.digitization.config"].search([], limit=1)
        if not config:
            return {
                "type": "ir.actions.client",
                "tag": "display_notification",
                "params": {
                    "title": _("Document Digitization Test"),
                    "message": _("No Document Digitization configuration found. Configure it first."),
                    "type": "warning",
                    "sticky": False,
                },
            }
        return config.action_test_connection()

FinancePPMDashboard(http.Controller):

    @http.route(
        "/finance-ppm/okr-dashboard/data",
        auth="user",
        type="json",
        methods=["POST"],
    )
    def okr_dashboard_data(self):
        """
        Returns live task counts by stage for Finance PPM projects.
        Response shape:
          {
            team: [{name, tasks_total, tasks_done, pct}],
            stages: {<stage_name>: <count>},
            totals: {total, done, pct},
          }
        """
        env = request.env

        # Finance PPM projects identified by cost center field presence
        projects = env["project.project"].search([
            ("ipai_ppm_cost_center", "!=", False),
        ])
        project_ids = projects.ids

        if not project_ids:
            return {"error": "Finance PPM projects not found"}

        # Per-user task counts — all users assigned to Finance PPM tasks
        all_tasks = env["project.task"].search([
            ("project_id", "in", project_ids),
            ("user_ids", "!=", False),
        ])
        user_ids = all_tasks.mapped("user_ids")

        team = []
        for u in user_ids:
            assigned = env["project.task"].search_count([
                ("project_id", "in", project_ids),
                ("user_ids", "in", [u.id]),
            ])
            done = env["project.task"].search_count([
                ("project_id", "in", project_ids),
                ("user_ids", "in", [u.id]),
                ("stage_id.fold", "=", True),
            ])
            pct = round(done / assigned * 100, 1) if assigned else 0
            team.append({
                "id": u.id,
                "name": u.name,
                "tasks_total": assigned,
                "tasks_done": done,
                "pct": pct,
            })

        # Stage distribution
        stages = env["project.task.type"].search([
            ("project_ids", "in", project_ids),
        ])
        stage_counts = {}
        for s in stages:
            cnt = env["project.task"].search_count([
                ("project_id", "in", project_ids),
                ("stage_id", "=", s.id),
            ])
            stage_counts[s.name] = cnt

        # Totals
        total = env["project.task"].search_count([
            ("project_id", "in", project_ids),
        ])
        done_total = env["project.task"].search_count([
            ("project_id", "in", project_ids),
            ("stage_id.fold", "=", True),
        ])

        return {
            "team": team,
            "stages": stage_counts,
            "totals": {
                "total": total,
                "done": done_total,
                "pct": round(done_total / total * 100, 1) if total else 0,
            },
        }

from odoo import api, fields, models

class AccountAnalyticAccount(models.Model):
    _inherit = "account.analytic.account"

    ipai_ppm_budget_amount = fields.Monetary(
        string="PPM Budget",
        currency_field="currency_id",
        tracking=True,
    )
    ipai_ppm_budget_source_project_id = fields.Many2one(
        "project.project",
        string="Budget Source Project",
        index=True,
        readonly=True,
    )
    ipai_ppm_import_batch_id = fields.Char(string="Import Batch ID", index=True, readonly=True)
    ipai_ppm_imported_at = fields.Datetime(string="Imported At", readonly=True)
    ipai_ppm_import_source = fields.Char(string="Import Source", readonly=True)

    @api.model
    def ipai_sync_project_budget_to_analytic(self, project_id):
        p = self.env["project.project"].browse(project_id)
        if not p.exists():
            return False
        aa = p.analytic_account_id
        if not aa:
            return False
        aa.write({
            "ipai_ppm_budget_amount": p.ipai_ppm_budget_amount,
            "ipai_ppm_budget_source_project_id": p.id,
        })
        return True

ProjectTaskIntegration(models.Model):
    _inherit = 'project.task'

    def _is_finance_ppm_task(self):
        """Check if task belongs to a Finance PPM project (by project name convention)."""
        if not self.project_id:
            return False
        return 'Finance PPM' in (self.project_id.name or '')

    @api.model_create_multi
    def create(self, vals_list):
        """Override: Emit finance_task.created for Finance PPM tasks"""
        tasks = super().create(vals_list)

        for task in tasks.filtered(lambda t: t._is_finance_ppm_task()):
            self._emit_finance_task_event(task, 'finance_task.created')

        return tasks

    def write(self, vals):
        """Override: Emit events when task state changes"""
        res = super().write(vals)

        if 'stage_id' in vals:
            for task in self:
                if task._is_finance_ppm_task():
                    event_type = self._get_event_type_for_stage(task)
                    if event_type:
                        self._emit_finance_task_event(task, event_type)

        return res

    def _get_event_type_for_stage(self, task):
        """Map task stage to event type"""
        if not task.stage_id:
            return None

        stage_name = task.stage_id.name.lower()

        if 'progress' in stage_name or 'doing' in stage_name or 'preparation' in stage_name:
            return 'finance_task.in_progress'
        elif 'review' in stage_name or 'submitted' in stage_name:
            return 'finance_task.submitted'
        elif 'done' in stage_name or 'approved' in stage_name:
            return 'finance_task.approved'
        elif 'filed' in stage_name:
            return 'finance_task.filed'

        return None

    def _emit_finance_task_event(self, task, event_type):
        """Emit finance task event to integration bus"""
        if send_ipai_event is None:
            return

        webhook_url = self.env['ir.config_parameter'].sudo().get_param('ipai.webhook.url')
        webhook_secret = self.env['ir.config_parameter'].sudo().get_param('ipai.webhook.secret')

        if not webhook_url or not webhook_secret:
            _logger.warning("IPAI webhook not configured — skipping event emission")
            return

        # Build payload using Odoo-native fields only
        tag_names = task.tag_ids.mapped('name') if task.tag_ids else []
        payload = {
            "task_id": task.id,
            "task_name": task.name,
            "project_name": task.project_id.name if task.project_id else "",
            "status": task.stage_id.name if task.stage_id else None,
            "new_stage": task.stage_id.name if task.stage_id else None,
            "assigned_to": task.user_ids[0].name if task.user_ids else None,
            "date_deadline": task.date_deadline.isoformat() if task.date_deadline else None,
            "tags": tag_names,
            "milestone": task.milestone_id.name if task.milestone_id else None,
            "assignee_emails": [u.email for u in task.user_ids if u.email],
            "write_date_unix": int(task.write_date.timestamp()) if task.write_date else 0,
        }

        event = {
            "event_type": event_type,
            "aggregate_type": "finance_task",
            "aggregate_id": str(task.id),
            "payload": payload,
        }

        idempotency_key = f"{event_type}:{task.id}:{task.write_date.timestamp()}"

        try:
            send_ipai_event(webhook_url, webhook_secret, event, idempotency_key=idempotency_key)
            _logger.info("Emitted %s event for task #%s", event_type, task.id)
        except Exception as e:
            _logger.error("Failed to emit %s event: %s", event_type, e)

    @api.model
    def _cron_detect_overdue_finance_tasks(self):
        """
        Cron job to detect overdue finance tasks.
        Uses Odoo-native date_deadline field on project.task.
        Run daily to check for deadline breaches.
        """
        if send_ipai_event is None:
            return

        webhook_url = self.env['ir.config_parameter'].sudo().get_param('ipai.webhook.url')
        webhook_secret = self.env['ir.config_parameter'].sudo().get_param('ipai.webhook.secret')

        if not webhook_url or not webhook_secret:
            return

        # Find tasks past their deadline and not yet completed
        # Uses Odoo-native date_deadline field
        done_stage_ids = self.env['project.task.type'].search([
            ('name', 'in', ['Done', 'Filed', 'Cancelled']),
        ]).ids

        overdue_tasks = self.search([
            ('date_deadline', '<', fields.Date.today()),
            ('date_deadline', '!=', False),
            ('stage_id', 'not in', done_stage_ids),
            ('project_id.name', 'ilike', 'Finance PPM'),
        ])

        for task in overdue_tasks:
            days_overdue = (fields.Date.today() - task.date_deadline).days if task.date_deadline else 0
            event = {
                "event_type": "finance_task.overdue",
                "aggregate_type": "finance_task",
                "aggregate_id": str(task.id),
                "payload": {
                    "task_id": task.id,
                    "task_name": task.name,
                    "project_name": task.project_id.name if task.project_id else "",
                    "date_deadline": task.date_deadline.isoformat() if task.date_deadline else None,
                    "days_overdue": days_overdue,
                    "assigned_to": task.user_ids[0].name if task.user_ids else None,
                    "status": task.stage_id.name if task.stage_id else None,
                    "tags": task.tag_ids.mapped('name') if task.tag_ids else [],
                },
            }

            idempotency_key = f"finance_task.overdue:{task.id}:{fields.Date.today().isoformat()}"

            try:
                send_ipai_event(webhook_url, webhook_secret, event, idempotency_key=idempotency_key)
                _logger.info("Emitted finance_task.overdue event for task #%s", task.id)
            except Exception as e:
                _logger.error("Failed to emit finance_task.overdue event: %s", e)

        _logger.info("Overdue finance task detection completed — %d overdue tasks found", len(overdue_tasks))

# -*- coding: utf-8 -*-
from odoo import _, api, models
from odoo.exceptions import ValidationError


class HrExpenseSheetCAConstraint(models.Model):
    _inherit = "hr.expense.sheet"

    @api.constrains("expense_line_ids")
    def _check_single_cash_advance_per_sheet(self):
        for sheet in self:
            liq_ids = sheet.expense_line_ids.mapped(
                "cash_advance_liquidation_id"
            ).filtered(bool)
            if len(liq_ids) > 1:
                raise ValidationError(_(
                    "All expense lines must reference the same Cash Advance "
                    "Liquidation form. Found: %s",
                    ", ".join(liq_ids.mapped("name")),
                ))

CopilotGatewayController(http.Controller):
    """Controller bridging the systray copilot UI to Azure Foundry / OpenAI.

    Supports two backends:
    - Track 1: Azure OpenAI Chat Completions (immediate, env-var based)
    - Track 2: Custom gateway endpoint (for Foundry Agent SDK / agent-platform)

    Backend is selected automatically:
    - If AZURE_FOUNDRY_API_KEY env var is set → Track 1 (direct OpenAI)
    - Otherwise → Track 2 (custom gateway URL from ir.config_parameter)
    """

    # ------------------------------------------------------------------
    # Rate limiting & validation
    # ------------------------------------------------------------------

    def _check_rate_limit(self, uid):
        """Enforce per-user rate limiting. Returns True if allowed."""
        now = time.monotonic()
        with _rate_limit_lock:
            bucket = _rate_limit_buckets[uid]
            # Purge expired entries
            while bucket and bucket[0] < now - _RATE_LIMIT_WINDOW:
                bucket.popleft()
            if len(bucket) >= _RATE_LIMIT_MAX_REQUESTS:
                return False
            bucket.append(now)
            return True

    def _validate_message(self, message):
        """Validate message content. Returns error string or None."""
        if not message or not message.strip():
            return 'Message cannot be empty.'
        if len(message) > _MAX_MESSAGE_LENGTH:
            return 'Message exceeds maximum length of %d characters.' % _MAX_MESSAGE_LENGTH
        return None

    def _validate_context(self, context):
        """Validate context fields. Returns sanitized context dict."""
        ctx = {}
        model = context.get('context_model', '')
        if model:
            # Only allow valid Odoo model name patterns
            if not all(c.isalnum() or c in '._ ' for c in model):
                model = ''
        ctx['context_model'] = model

        res_id = context.get('context_res_id', 0)
        try:
            ctx['context_res_id'] = max(0, int(res_id))
        except (ValueError, TypeError):
            ctx['context_res_id'] = 0

        ctx['surface'] = context.get('surface', 'erp')
        return ctx

    def _check_conversation_access(self, conversation):
        """Check user + company access to a conversation. Returns error or None."""
        if conversation.user_id != request.env.user:
            return 'Access denied to this conversation.'
        if conversation.company_id and conversation.company_id != request.env.company:
            return 'Access denied: conversation belongs to a different company.'
        return None

    def _audit_log(self, event_type, **kwargs):
        """Write an audit log entry. Swallows errors to never block requests."""
        try:
            ip = request.httprequest.remote_addr or ''
            request.env['ipai.copilot.audit'].log_event(
                event_type, ip_address=ip, **kwargs,
            )
        except Exception:
            pass

    # ------------------------------------------------------------------
    # Helpers
    # ------------------------------------------------------------------

    def _get_gateway_url(self):
        """Read gateway URL from ir.config_parameter."""
        return (
            request.env['ir.config_parameter']
            .sudo()
            .get_param('ipai.copilot.gateway_url', 'http://localhost:8088')
        )

    def _is_enabled(self):
        """Check if copilot is enabled via ir.config_parameter."""
        val = (
            request.env['ir.config_parameter']
            .sudo()
            .get_param('ipai.copilot.enabled', 'True')
        )
        return val.lower() in ('true', '1', 'yes')

    def _get_mode(self):
        """Read copilot operating mode."""
        return (
            request.env['ir.config_parameter']
            .sudo()
            .get_param('ipai.copilot.mode', 'PROD-ADVISORY')
        )

    def _get_backend(self):
        """Determine which backend to use.

        Returns ('openai', endpoint, api_key) or ('gateway', url, None).

        Auth priority:
        1. API key via AZURE_FOUNDRY_API_KEY (non-prod bootstrap)
        2. Managed identity via DefaultAzureCredential (production)
        3. Fall back to custom gateway URL
        """
        import os
        api_key = os.getenv('AZURE_FOUNDRY_API_KEY', '')
        endpoint = os.getenv(
            'AZURE_OPENAI_ENDPOINT',
            'https://ipai-copilot-resource.openai.azure.com/openai/v1',
        )
        if api_key:
            return 'openai', endpoint, api_key
        # Try managed identity (DefaultAzureCredential) for keyless auth
        token = self._get_managed_identity_token()
        if token:
            return 'openai', endpoint, token
        return 'gateway', self._get_gateway_url(), None

    def _get_managed_identity_token(self):
        """Acquire a bearer token via managed identity. Returns token or None."""
        try:
            from azure.identity import DefaultAzureCredential
            credential = DefaultAzureCredential()
            token = credential.get_token('https://cognitiveservices.azure.com/.default')
            return token.token
        except Exception:
            return None

    def _call_openai(self, messages, correlation_id):
        """Call Azure OpenAI Chat Completions API.

        Args:
            messages: List of {role, content} dicts.
            correlation_id: Correlation ID for tracing.

        Returns:
            (response_dict, latency_ms) on success.
        """
        _, endpoint, auth_value = self._get_backend()
        model = (
            request.env['ir.config_parameter']
            .sudo()
            .get_param('ipai.copilot.model', 'gpt-4.1')
        )
        # Azure OpenAI uses /openai/deployments/{model}/chat/completions
        base = endpoint.rstrip('/')
        if '/openai/v1' in base:
            base = base.split('/openai/v1')[0]
        url = (
            f"{base}/openai/deployments/{model}"
            f"/chat/completions?api-version=2024-08-01-preview"
        )

        payload = {
            'model': model,
            'messages': messages,
            'temperature': 0.4,
            'max_tokens': 2048,
        }
        body = json.dumps(payload).encode('utf-8')
        headers = {
            'Content-Type': 'application/json',
            'X-Correlation-Id': correlation_id,
        }
        # Support both API key and Bearer token (managed identity)
        import os
        if os.getenv('AZURE_FOUNDRY_API_KEY', ''):
            headers['api-key'] = auth_value
        else:
            headers['Authorization'] = 'Bearer %s' % auth_value

        req = urllib.request.Request(url, data=body, headers=headers, method='POST')
        start = time.monotonic()
        try:
            with urllib.request.urlopen(req, timeout=_GATEWAY_TIMEOUT) as resp:
                latency_ms = int((time.monotonic() - start) * 1000)
                data = json.loads(resp.read().decode('utf-8', errors='replace'))
                content = ''
                if data.get('choices'):
                    content = data['choices'][0].get('message', {}).get('content', '')
                return {'content': content, 'request_id': correlation_id}, latency_ms
        except urllib.error.HTTPError as e:
            latency_ms = int((time.monotonic() - start) * 1000)
            error_body = ''
            try:
                error_body = e.read().decode('utf-8', errors='replace')
            except Exception:
                pass
            _logger.warning(
                'OpenAI HTTP %d: %s (latency=%dms)', e.code, error_body[:300], latency_ms,
            )
            raise ValueError('OpenAI returned HTTP %d: %s' % (e.code, e.reason))
        except urllib.error.URLError as e:
            raise ValueError('OpenAI unreachable: %s' % e.reason)
        except Exception as e:
            _logger.exception('OpenAI unexpected error')
            raise ValueError('OpenAI error: %s' % str(e))

    def _call_gateway(self, gateway_url, payload, correlation_id):
        """HTTP POST to the agent-platform gateway (Track 2).

        Returns (response_dict, latency_ms) on success.
        Raises ValueError on failure with a user-friendly message.
        """
        body = json.dumps(payload).encode('utf-8')
        headers = {
            'Content-Type': 'application/json',
            'Accept': 'application/json',
            'X-Correlation-Id': correlation_id,
            'X-Copilot-Mode': self._get_mode(),
        }

        req = urllib.request.Request(
            gateway_url, data=body, headers=headers, method='POST',
        )

        start = time.monotonic()
        try:
            with urllib.request.urlopen(req, timeout=_GATEWAY_TIMEOUT) as resp:
                latency_ms = int((time.monotonic() - start) * 1000)
                resp_body = resp.read().decode('utf-8', errors='replace')
                try:
                    data = json.loads(resp_body)
                except (json.JSONDecodeError, TypeError):
                    data = {'content': resp_body}
                return data, latency_ms
        except urllib.error.HTTPError as e:
            latency_ms = int((time.monotonic() - start) * 1000)
            error_body = ''
            try:
                error_body = e.read().decode('utf-8', errors='replace')
            except Exception:
                pass
            _logger.warning(
                'Copilot gateway HTTP %d: %s (latency=%dms)',
                e.code, error_body[:200], latency_ms,
            )
            raise ValueError(
                'Gateway returned HTTP %d: %s' % (e.code, e.reason)
            )
        except urllib.error.URLError as e:
            _logger.warning('Copilot gateway unreachable: %s', e.reason)
            raise ValueError(
                'Gateway unreachable at %s — %s' % (gateway_url, e.reason)
            )
        except Exception as e:
            _logger.exception('Copilot gateway unexpected error')
            raise ValueError('Gateway error: %s' % str(e))

    def _dispatch_message(self, message, context, conversation, correlation_id):
        """Route message to the appropriate backend.

        Returns (response_dict, latency_ms).
        """
        backend_type, url, _ = self._get_backend()

        if backend_type == 'openai':
            # Build OpenAI messages array with system prompt + context
            messages = [{'role': 'system', 'content': _SYSTEM_PROMPT}]

            # Add context hint if available
            ctx_model = context.get('context_model') or ''
            ctx_id = context.get('context_res_id') or 0
            if ctx_model:
                messages.append({
                    'role': 'system',
                    'content': 'User is viewing %s (ID: %s) in Odoo.' % (ctx_model, ctx_id),
                })

            # Add conversation history (last 10 messages)
            if conversation:
                history = request.env['ipai.copilot.message'].sudo().search(
                    [('conversation_id', '=', conversation.id)],
                    order='create_date asc',
                    limit=10,
                )
                for msg in history:
                    if msg.role in ('user', 'assistant'):
                        messages.append({'role': msg.role, 'content': msg.content or ''})

            messages.append({'role': 'user', 'content': message})
            return self._call_openai(messages, correlation_id)
        else:
            # Track 2: Custom gateway
            payload = {
                'conversation_id': str(conversation.id) if conversation else '',
                'correlation_id': correlation_id,
                'message': message,
                'user': {
                    'uid': request.env.user.id,
                    'name': request.env.user.name,
                    'login': request.env.user.login,
                },
                'context': context,
                'mode': self._get_mode(),
            }
            return self._call_gateway(url, payload, correlation_id)

    # ------------------------------------------------------------------
    # Routes
    # ------------------------------------------------------------------

    @http.route(
        '/ipai/copilot/chat',
        type='json',
        auth='user',
        methods=['POST'],
    )
    def chat(self, conversation_id=None, message='', context=None):
        """Send a message to the copilot and return the response.

        Args:
            conversation_id: Optional ID of an existing conversation.
            message: The user's message text.
            context: Optional dict with context_model, context_res_id, etc.

        Returns:
            dict with keys: conversation_id, content, role, request_id,
            latency_ms, error (if any).
        """
        if not self._is_enabled():
            return {
                'error': True,
                'message': 'Copilot is disabled. Enable it in Settings.',
            }

        # Rate limiting
        uid = request.env.uid
        if not self._check_rate_limit(uid):
            self._audit_log('rate_limited', user_id=uid)
            return {
                'error': True,
                'message': 'Rate limit exceeded. Please wait before sending more messages.',
            }

        # Input validation
        validation_error = self._validate_message(message)
        if validation_error:
            self._audit_log('validation_error', user_id=uid,
                            error_detail=validation_error)
            return {
                'error': True,
                'message': validation_error,
            }

        context = self._validate_context(context or {})
        Conversation = request.env['ipai.copilot.conversation']
        Message = request.env['ipai.copilot.message']

        # Get or create conversation
        if conversation_id:
            conversation = Conversation.browse(conversation_id).exists()
            if not conversation:
                return {
                    'error': True,
                    'message': 'Conversation not found.',
                }
            # Security: user + company access check
            access_error = self._check_conversation_access(conversation)
            if access_error:
                self._audit_log('access_denied', user_id=uid,
                                conversation_id=conversation.id,
                                error_detail=access_error)
                return {
                    'error': True,
                    'message': access_error,
                }
        else:
            conv_vals = {
                'name': (message or '')[:80] or 'New Conversation',
            }
            if context.get('context_model'):
                conv_vals['context_model'] = context['context_model']
            if context.get('context_res_id'):
                conv_vals['context_res_id'] = int(context['context_res_id'])
            conversation = Conversation.create(conv_vals)

        # Persist user message
        user_msg = Message.create({
            'conversation_id': conversation.id,
            'role': 'user',
            'content': message.strip(),
        })

        # Dispatch to backend (OpenAI or custom gateway)
        correlation_id = conversation.gateway_correlation_id or str(uuid.uuid4())
        ctx = {
            'context_model': context.get('context_model') or conversation.context_model or '',
            'context_res_id': context.get('context_res_id') or conversation.context_res_id or 0,
            'surface': context.get('surface', 'erp'),
        }

        self._audit_log('chat_request', user_id=uid,
                        conversation_id=conversation.id,
                        correlation_id=correlation_id,
                        payload_summary=message[:200])

        try:
            resp_data, latency_ms = self._dispatch_message(
                message.strip(), ctx, conversation, correlation_id
            )
        except ValueError as e:
            # Persist error as system message for audit trail
            Message.create({
                'conversation_id': conversation.id,
                'role': 'system',
                'content': 'Gateway error: %s' % str(e),
            })
            self._audit_log('chat_error', user_id=uid,
                            conversation_id=conversation.id,
                            correlation_id=correlation_id,
                            error_detail=str(e)[:500])
            return {
                'error': True,
                'message': str(e),
                'conversation_id': conversation.id,
            }

        # Extract response content
        assistant_content = (
            resp_data.get('content')
            or resp_data.get('message')
            or resp_data.get('response')
            or 'No response content received.'
        )
        tool_calls = resp_data.get('tool_calls')
        request_id = resp_data.get('request_id', correlation_id)

        # Persist assistant message
        assistant_msg = Message.create({
            'conversation_id': conversation.id,
            'role': 'assistant',
            'content': assistant_content,
            'tool_calls': tool_calls,
            'latency_ms': latency_ms,
            'request_id': request_id,
        })

        self._audit_log('chat_response', user_id=uid,
                        conversation_id=conversation.id,
                        correlation_id=correlation_id,
                        latency_ms=latency_ms)

        return {
            'conversation_id': conversation.id,
            'content': assistant_content,
            'role': 'assistant',
            'request_id': request_id,
            'latency_ms': latency_ms,
            'tool_calls': tool_calls,
        }

    @http.route(
        '/ipai/copilot/stream',
        type='http',
        auth='user',
        methods=['POST'],
        csrf=True,
    )
    def stream_chat(self, **kwargs):
        """Stream a copilot response via Server-Sent Events.

        Accepts form-encoded or JSON body with: message, conversation_id,
        context_model, context_res_id, surface, csrf_token.

        Returns text/event-stream with data chunks as they arrive from
        the gateway. Falls back to a single-event response if the gateway
        does not support streaming.
        """
        if not self._is_enabled():
            return WerkzeugResponse(
                'data: {"error": true, "message": "Copilot is disabled."}\n\n',
                content_type='text/event-stream',
                status=200,
            )

        # Rate limiting
        uid = request.env.uid
        if not self._check_rate_limit(uid):
            self._audit_log('rate_limited', user_id=uid)
            return WerkzeugResponse(
                'data: {"error": true, "message": "Rate limit exceeded."}\n\n',
                content_type='text/event-stream',
                status=429,
            )

        # Parse input — accept both JSON body and form params
        try:
            body = json.loads(request.httprequest.get_data(as_text=True))
        except (json.JSONDecodeError, TypeError):
            body = {}
        message = body.get('message') or kwargs.get('message', '')
        conversation_id = body.get('conversation_id') or kwargs.get('conversation_id')
        raw_context = {
            'context_model': body.get('context_model') or kwargs.get('context_model', ''),
            'context_res_id': body.get('context_res_id') or kwargs.get('context_res_id', 0),
            'surface': body.get('surface') or kwargs.get('surface', 'erp'),
        }
        context = self._validate_context(raw_context)

        message = (message or '').strip()
        validation_error = self._validate_message(message)
        if validation_error:
            self._audit_log('validation_error', user_id=uid,
                            error_detail=validation_error)
            return WerkzeugResponse(
                'data: %s\n\n' % json.dumps({'error': True, 'message': validation_error}),
                content_type='text/event-stream',
                status=200,
            )

        Conversation = request.env['ipai.copilot.conversation']
        Message = request.env['ipai.copilot.message']

        # Get or create conversation
        if conversation_id:
            try:
                conversation_id = int(conversation_id)
            except (ValueError, TypeError):
                conversation_id = None

        if conversation_id:
            conversation = Conversation.browse(conversation_id).exists()
            if not conversation:
                return WerkzeugResponse(
                    'data: {"error": true, "message": "Conversation not found."}\n\n',
                    content_type='text/event-stream',
                    status=200,
                )
            access_error = self._check_conversation_access(conversation)
            if access_error:
                self._audit_log('access_denied', user_id=uid,
                                conversation_id=conversation.id,
                                error_detail=access_error)
                return WerkzeugResponse(
                    'data: %s\n\n' % json.dumps({'error': True, 'message': access_error}),
                    content_type='text/event-stream',
                    status=200,
                )
        else:
            conv_vals = {
                'name': message[:80] or 'New Conversation',
            }
            if context.get('context_model'):
                conv_vals['context_model'] = context['context_model']
            if context.get('context_res_id'):
                conv_vals['context_res_id'] = int(context['context_res_id'])
            conversation = Conversation.create(conv_vals)

        # Persist user message before streaming
        Message.create({
            'conversation_id': conversation.id,
            'role': 'user',
            'content': message,
        })

        correlation_id = conversation.gateway_correlation_id or str(uuid.uuid4())
        gateway_url = self._get_gateway_url()
        payload = {
            'conversation_id': str(conversation.id),
            'correlation_id': correlation_id,
            'message': message,
            'user': {
                'uid': request.env.user.id,
                'name': request.env.user.name,
                'login': request.env.user.login,
            },
            'context': {
                'model': context.get('context_model') or conversation.context_model or '',
                'res_id': context.get('context_res_id') or conversation.context_res_id or 0,
                'surface': context.get('surface', 'erp'),
            },
            'mode': self._get_mode(),
            'stream': True,
        }

        self._audit_log('stream_request', user_id=uid,
                        conversation_id=conversation.id,
                        correlation_id=correlation_id,
                        payload_summary=message[:200])

        # Capture env references before generator (request context may expire)
        env = request.env
        conv_id = conversation.id
        audit_uid = uid

        def generate():
            """SSE generator that proxies gateway streaming response."""
            full_content = ''
            start = time.monotonic()
            error_occurred = False
            disconnected = False

            try:
                import requests as http_requests
            except ImportError:
                # Fall back to urllib if requests not available
                http_requests = None

            try:
                # Send initial event with conversation_id
                yield 'data: %s\n\n' % json.dumps({
                    'type': 'start',
                    'conversation_id': conv_id,
                })

                if http_requests:
                    resp = http_requests.post(
                        gateway_url,
                        json=payload,
                        stream=True,
                        timeout=60,
                        headers={
                            'Content-Type': 'application/json',
                            'Accept': 'text/event-stream',
                            'X-Correlation-Id': correlation_id,
                            'X-Copilot-Mode': payload['mode'],
                        },
                    )
                    resp.raise_for_status()

                    for line in resp.iter_lines(decode_unicode=True):
                        if not line:
                            continue
                        # Handle SSE format from gateway
                        if line.startswith('data: '):
                            chunk_data = line[6:]
                            try:
                                chunk = json.loads(chunk_data)
                                token = chunk.get('content') or chunk.get('token') or chunk.get('delta', '')
                            except (json.JSONDecodeError, TypeError):
                                token = chunk_data
                            if token:
                                full_content += token
                                yield 'data: %s\n\n' % json.dumps({
                                    'type': 'chunk',
                                    'content': token,
                                    'full_content': full_content,
                                })
                        elif not line.startswith(':'):
                            # Non-SSE response — treat entire line as content
                            full_content += line
                            yield 'data: %s\n\n' % json.dumps({
                                'type': 'chunk',
                                'content': line,
                                'full_content': full_content,
                            })
                else:
                    # Fallback: non-streaming via urllib
                    try:
                        data, latency_ms = self._call_gateway(
                            gateway_url, payload, correlation_id
                        )
                        full_content = (
                            data.get('content')
                            or data.get('message')
                            or data.get('response')
                            or 'No response content received.'
                        )
                        yield 'data: %s\n\n' % json.dumps({
                            'type': 'chunk',
                            'content': full_content,
                            'full_content': full_content,
                        })
                    except ValueError as e:
                        error_occurred = True
                        yield 'data: %s\n\n' % json.dumps({
                            'type': 'error',
                            'message': str(e),
                        })

            except GeneratorExit:
                # Client disconnected mid-stream
                disconnected = True
                _logger.info('Client disconnected during stream (conv=%s)', conv_id)
            except Exception as e:
                error_occurred = True
                _logger.warning('Copilot stream error: %s', e)
                yield 'data: %s\n\n' % json.dumps({
                    'type': 'error',
                    'message': 'Stream error: %s' % str(e),
                })

            latency_ms = int((time.monotonic() - start) * 1000)

            # Persist assistant message after stream completes
            # On disconnect with partial content, still persist what we have
            if full_content and not error_occurred:
                try:
                    with env.registry.cursor() as cr:
                        new_env = env(cr=cr)
                        new_env['ipai.copilot.message'].create({
                            'conversation_id': conv_id,
                            'role': 'assistant',
                            'content': full_content,
                            'latency_ms': latency_ms,
                            'request_id': correlation_id,
                        })
                        # Audit log within same cursor
                        event = 'stream_disconnect' if disconnected else 'stream_complete'
                        new_env['ipai.copilot.audit'].log_event(
                            event,
                            user_id=audit_uid,
                            conversation_id=conv_id,
                            correlation_id=correlation_id,
                            latency_ms=latency_ms,
                        )
                except Exception as e:
                    _logger.warning('Failed to persist streamed response: %s', e)
            elif error_occurred:
                try:
                    with env.registry.cursor() as cr:
                        new_env = env(cr=cr)
                        new_env['ipai.copilot.audit'].log_event(
                            'stream_error',
                            user_id=audit_uid,
                            conversation_id=conv_id,
                            correlation_id=correlation_id,
                            latency_ms=latency_ms,
                        )
                except Exception:
                    pass

            if not disconnected:
                # Send done event
                yield 'data: %s\n\n' % json.dumps({
                    'type': 'done',
                    'latency_ms': latency_ms,
                    'conversation_id': conv_id,
                })

        return WerkzeugResponse(
            generate(),
            content_type='text/event-stream',
            headers={
                'Cache-Control': 'no-cache',
                'X-Accel-Buffering': 'no',
            },
        )

    @http.route(
        '/ipai/copilot/conversations/create',
        type='json',
        auth='user',
        methods=['POST'],
    )
    def create_conversation(self, name='', context_model='', context_res_id=0):
        """Create a new conversation.

        Returns:
            dict with conversation_id, name, gateway_correlation_id.
        """
        if not self._is_enabled():
            return {
                'error': True,
                'message': 'Copilot is disabled.',
            }

        vals = {
            'name': name or 'New Conversation',
        }
        if context_model:
            vals['context_model'] = context_model
        if context_res_id:
            vals['context_res_id'] = int(context_res_id)

        conversation = request.env['ipai.copilot.conversation'].create(vals)
        return {
            'conversation_id': conversation.id,
            'name': conversation.name,
            'gateway_correlation_id': conversation.gateway_correlation_id,
        }

    @http.route(
        '/ipai/copilot/conversations/list',
        type='json',
        auth='user',
        methods=['POST'],
    )
    def list_conversations(self, state='active', limit=20, offset=0):
        """Return current user's conversations.

        Returns:
            dict with conversations list and total count.
        """
        if not self._is_enabled():
            return {
                'error': True,
                'message': 'Copilot is disabled.',
            }

        Conversation = request.env['ipai.copilot.conversation']
        domain = [
            ('user_id', '=', request.env.user.id),
        ]
        if state:
            domain.append(('state', '=', state))

        total = Conversation.search_count(domain)
        conversations = Conversation.search(
            domain, limit=limit, offset=offset,
        )

        return {
            'conversations': [
                {
                    'id': c.id,
                    'name': c.name,
                    'state': c.state,
                    'message_count': c.message_count,
                    'context_model': c.context_model or '',
                    'context_res_id': c.context_res_id or 0,
                    'create_date': str(c.create_date),
                    'write_date': str(c.write_date),
                }
                for c in conversations
            ],
            'total': total,
        }

CopilotController(http.Controller):

    # ------------------------------------------------------------------
    # Chat endpoints
    # ------------------------------------------------------------------

    @http.route(
        "/ipai/copilot/chat",
        type="json",
        auth="user",
        methods=["POST"],
        csrf=True,
    )
    def chat(self, prompt=None, message=None, record_model=None,
             record_id=None, surface=None, conversation_id=None,
             context=None, **kw):
        """Chat endpoint for Odoo-authenticated consumers.

        Accepts both formats:
          - systray UI: {"message": "...", "conversation_id": N, "context": {...}}
          - API:        {"prompt": "...", "record_model": "...", "record_id": 123}

        Returns: {"content": "...", "blocked": false, "reason": "",
                  "conversation_id": N}
        """
        # Normalize: accept 'message' (from UI) or 'prompt' (from API)
        text = prompt or message
        ctx = context or {}
        return self._handle_chat(
            prompt=text,
            record_model=record_model or ctx.get("context_model"),
            record_id=record_id or ctx.get("context_res_id"),
            source="api",
            user_id=request.env.uid,
            surface=surface or ctx.get("surface") or "erp",
            conversation_id=conversation_id,
        )

    @http.route(
        "/ipai/copilot/chat/service",
        type="json",
        auth="none",
        methods=["POST"],
        csrf=False,
    )
    def chat_service(self, prompt=None, record_model=None,
                     record_id=None, surface=None, **kw):
        """Service-to-service endpoint for external apps (docs widget).

        Authenticates via IPAI_COPILOT_SERVICE_KEY header.
        Audit records are logged with source='widget'.
        """
        expected_key = os.environ.get("IPAI_COPILOT_SERVICE_KEY", "")
        if not expected_key:
            _logger.warning(
                "Service endpoint called but IPAI_COPILOT_SERVICE_KEY "
                "not configured"
            )
            return {
                "content": "",
                "blocked": True,
                "reason": "Service key not configured on server",
            }

        provided_key = (
            request.httprequest.headers.get("X-Copilot-Service-Key", "")
        )
        if not provided_key or not hmac.compare_digest(
            expected_key, provided_key
        ):
            return {
                "content": "",
                "blocked": True,
                "reason": "Invalid service key",
            }

        # Use sudo env — resolve a bot user for audit trail
        bot_partner = request.env(su=True).ref(
            "ipai_odoo_copilot.partner_copilot", raise_if_not_found=False
        )
        bot_user_id = None
        if bot_partner:
            bot_user = request.env(su=True)["res.users"].search(
                [("partner_id", "=", bot_partner.id)], limit=1
            )
            bot_user_id = bot_user.id if bot_user else None

        return self._handle_chat(
            prompt=prompt,
            record_model=record_model,
            record_id=record_id,
            source="widget",
            user_id=bot_user_id,
            sudo=True,
            surface=surface or "web",
        )

    def _handle_chat(self, prompt, record_model, record_id, source,
                     user_id, sudo=False, surface="erp",
                     conversation_id=None):
        """Shared chat handler for both authenticated and service routes."""
        if not prompt:
            return {"content": "", "blocked": True, "reason": "Empty prompt"}

        env = request.env
        if sudo:
            env = env(su=True)

        service = env["ipai.foundry.service"]
        settings = service._get_settings()

        if not settings["enabled"]:
            return {
                "content": "",
                "blocked": True,
                "reason": "Copilot is disabled",
            }

        # Build context envelope from authenticated user
        context_envelope = service._build_context_envelope(
            user_id=user_id or env.uid,
            record_model=record_model,
            record_id=record_id,
            surface=surface,
        )

        # Build context hint if record info provided
        context_prefix = ""
        if record_model and record_id:
            context_prefix = (
                "[Context: viewing %s record #%s] "
                % (record_model, record_id)
            )

        user_message = context_prefix + prompt

        response_text = service.chat_completion(
            user_message=user_message,
            user_id=user_id,
            context_envelope=context_envelope,
        )

        return {
            "content": response_text or "",
            "blocked": not bool(response_text),
            "reason": "" if response_text else "No response from Foundry",
            "conversation_id": conversation_id,
        }

    # ------------------------------------------------------------------
    # Conversation CRUD (used by systray copilot_service.js)
    # ------------------------------------------------------------------

    def _is_enabled(self):
        """Check if copilot is enabled via ir.config_parameter."""
        return request.env["ir.config_parameter"].sudo().get_param(
            "ipai_copilot.enabled", "False"
        ).lower() in ("true", "1")

    @http.route(
        "/ipai/copilot/conversations/create",
        type="json",
        auth="user",
        methods=["POST"],
    )
    def create_conversation(self, name="", context_model="",
                            context_res_id=0):
        """Create a new conversation."""
        if not self._is_enabled():
            return {"error": True, "message": "Copilot is disabled."}

        vals = {"name": name or "New Conversation"}
        if context_model:
            vals["context_model"] = context_model
        if context_res_id:
            vals["context_res_id"] = int(context_res_id)

        conversation = request.env["ipai.copilot.conversation"].create(vals)
        return {
            "conversation_id": conversation.id,
            "name": conversation.name,
            "gateway_correlation_id": conversation.gateway_correlation_id,
        }

    @http.route(
        "/ipai/copilot/conversations/list",
        type="json",
        auth="user",
        methods=["POST"],
    )
    def list_conversations(self, state="active", limit=20, offset=0):
        """Return current user's conversations."""
        if not self._is_enabled():
            return {"error": True, "message": "Copilot is disabled."}

        Conversation = request.env["ipai.copilot.conversation"]
        domain = [("user_id", "=", request.env.user.id)]
        if state:
            domain.append(("state", "=", state))

        total = Conversation.search_count(domain)
        conversations = Conversation.search(
            domain, limit=limit, offset=offset,
        )

        return {
            "conversations": [
                {
                    "id": c.id,
                    "name": c.name,
                    "state": c.state,
                    "message_count": c.message_count,
                    "context_model": c.context_model or "",
                    "context_res_id": c.context_res_id or 0,
                    "create_date": str(c.create_date),
                    "write_date": str(c.write_date),
                }
                for c in conversations
            ],
            "total": total,
        }

