    )

    def action_test_copilot_connection(self):
        """Test the gateway connection by hitting its health endpoint."""
        self.ensure_one()
        gateway_url = (
            self.env['ir.config_parameter']
            .sudo()
            .get_param('ipai.copilot.gateway_url', '')
        )
        if not gateway_url:
            raise UserError(_('Gateway URL is not configured.'))

        health_url = gateway_url.rstrip('/') + '/health'
        try:
            req = urllib.request.Request(health_url, method='GET')
            with urllib.request.urlopen(req, timeout=10) as resp:
                status = resp.status
                body = resp.read().decode('utf-8', errors='replace')[:200]
        except urllib.error.HTTPError as e:
            raise UserError(
                _('Gateway returned HTTP %d: %s', e.code, e.reason)
            )
        except urllib.error.URLError as e:
            raise UserError(
                _('Gateway unreachable at %s — %s', health_url, e.reason)
            )
        except Exception as e:
            raise UserError(_('Connection error: %s', str(e)))

        if status == 200:
            return {
                'type': 'ir.actions.client',
                'tag': 'display_notification',
                'params': {
                    'title': _('Connection Successful'),
                    'message': _('Gateway is reachable at %s', gateway_url),
                    'type': 'success',
                    'sticky': False,
                },
            }
        raise UserError(
            _('Unexpected response: HTTP %d — %s', status, body)
        )

name.
            message: Error message string.
            properties: Additional context dimensions.
        """
        try:
            ikey, endpoint = self._parse_connection_string()
            if not ikey:
                return

            envelope = {
                "name": "Microsoft.ApplicationInsights.Exception",
                "time": time.strftime(
                    "%Y-%m-%dT%H:%M:%S.000Z", time.gmtime()
                ),
                "iKey": ikey,
                "data": {
                    "baseType": "ExceptionData",
                    "baseData": {
                        "ver": 2,
                        "exceptions": [
                            {
                                "typeName": exception_type,
                                "message": (message or "")[:1024],
                                "hasFullStack": False,
                            }
                        ],
                        "properties": properties or {},
                    },
                },
            }

            url = endpoint + _TRACK_PATH
            payload = json.dumps([envelope]).encode("utf-8")
            req = urllib.request.Request(
                url,
                data=payload,
                headers={"Content-Type": "application/json"},
                method="POST",
            )
            with urllib.request.urlopen(req, timeout=3):
                pass
        except Exception:
            _logger.debug(
                "App Insights exception telemetry failed",
                exc_info=True,
            )

